463: export function migrateTableDisplayModeToCellOptions(displayMode: TableCellDisplayMode): TableCellOptions {
464:   switch (displayMode) {
465:     // In the case of the gauge we move to a different option
466:     case 'basic':
467:     case 'gradient-gauge':
468:     case 'lcd-gauge':
469:       let gaugeMode = BarGaugeDisplayMode.Basic;
470: 
471:       if (displayMode === 'gradient-gauge') {
472:         gaugeMode = BarGaugeDisplayMode.Gradient;
473:       } else if (displayMode === 'lcd-gauge') {
474:         gaugeMode = BarGaugeDisplayMode.Lcd;
475:       }
476: 
477:       return {
478:         type: TableCellDisplayMode.Gauge,
479:         mode: gaugeMode,
480:       };
481:     // Also true in the case of the color background
482:     case 'color-background':
483:     case 'color-background-solid':
484:       let mode = TableCellBackgroundDisplayMode.Basic;
485: 
486:       // Set the new mode field, somewhat confusingly the
487:       // color-background mode is for gradient display
488:       if (displayMode === 'color-background') {
489:         mode = TableCellBackgroundDisplayMode.Gradient;
490:       }
491: 
492:       return {
493:         type: TableCellDisplayMode.ColorBackground,
494:         mode: mode,
495:       };
496:     default:
497:       return {
498:         // @ts-ignore
499:         type: displayMode,
500:       };
501:   }
502: }
